package com.quizverse.app.data.prepopulate

import com.quizverse.app.data.database.QuizDatabase
import com.quizverse.app.data.database.entities.Achievement
import com.quizverse.app.data.database.entities.Category
import com.quizverse.app.data.database.entities.Question
import com.quizverse.app.data.database.entities.UserProgress

/**
 * Seeds the database with initial data (categories, questions, achievements, user progress).
 * Called exactly once from [QuizDatabase.DatabaseCallback.onCreate].
 */
object QuestionSeeder {

    suspend fun seedDatabase(database: QuizDatabase) {
        insertCategories(database)
        insertQuestions(database)
        insertAchievements(database)
        insertInitialProgress(database)
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Categories
    // ─────────────────────────────────────────────────────────────────────────

    private suspend fun insertCategories(database: QuizDatabase) {
        val dao = database.questionDao()
        // Categories are inserted via a raw DAO call on the question dao which also owns the
        // category table access through the database reference.
        val categoryDao = database.questionDao()  // we use the db reference directly below

        // Build list of all 12 categories; questionCount reflects seeded data (25 each).
        val categories = listOf(
            Category(id = 1,  name = "Weltgeographie",      iconName = "🌍", gradientStartColor = 0xFF4FACFEL, gradientEndColor = 0xFF00F2FEL, questionCount = 25, isLocked = false),
            Category(id = 2,  name = "Wissenschaft & Natur",iconName = "🔬", gradientStartColor = 0xFF6C63FFL, gradientEndColor = 0xFFA855F7L, questionCount = 25, isLocked = false),
            Category(id = 3,  name = "Geschichte",          iconName = "📜", gradientStartColor = 0xFFF97316L, gradientEndColor = 0xFFFBBF24L, questionCount = 25, isLocked = false),
            Category(id = 4,  name = "Film & Fernsehen",    iconName = "🎬", gradientStartColor = 0xFFEC4899L, gradientEndColor = 0xFFF43F5EL, questionCount = 25, isLocked = false),
            Category(id = 5,  name = "Musik",               iconName = "🎵", gradientStartColor = 0xFF8B5CF6L, gradientEndColor = 0xFFC084FCL, questionCount = 25, isLocked = false),
            Category(id = 6,  name = "Sport",               iconName = "⚽", gradientStartColor = 0xFF22C55EL, gradientEndColor = 0xFF10B981L, questionCount = 25, isLocked = false),
            Category(id = 7,  name = "Technologie",         iconName = "💻", gradientStartColor = 0xFF3B82F6L, gradientEndColor = 0xFF6366F1L, questionCount = 25, isLocked = false),
            Category(id = 8,  name = "Essen & Trinken",     iconName = "🍳", gradientStartColor = 0xFFF59E0BL, gradientEndColor = 0xFFEF4444L, questionCount = 25, isLocked = false),
            Category(id = 9,  name = "Tierwelt",            iconName = "🐾", gradientStartColor = 0xFF14B8A6L, gradientEndColor = 0xFF06B6D4L, questionCount = 25, isLocked = false),
            Category(id = 10, name = "Sprache & Literatur", iconName = "📚", gradientStartColor = 0xFF8B5CF6L, gradientEndColor = 0xFFEC4899L, questionCount = 25, isLocked = false),
            Category(id = 11, name = "Bunt Gemischt",       iconName = "🎲", gradientStartColor = 0xFFF43F5EL, gradientEndColor = 0xFFF97316L, questionCount = 25, isLocked = false),
            Category(id = 12, name = "Logik & Denksport",   iconName = "🧠", gradientStartColor = 0xFF0EA5E9L, gradientEndColor = 0xFF6366F1L, questionCount = 25, isLocked = false),
        )

        // Insert categories using raw SQLite through the support DB to avoid a missing CategoryDao.
        categories.forEach { cat ->
            database.openHelper.writableDatabase.execSQL(
                """INSERT OR REPLACE INTO categories
                   (id, name, iconName, gradientStartColor, gradientEndColor, questionCount, isLocked)
                   VALUES (?, ?, ?, ?, ?, ?, ?)""",
                arrayOf(cat.id, cat.name, cat.iconName, cat.gradientStartColor, cat.gradientEndColor, cat.questionCount, if (cat.isLocked) 1 else 0)
            )
        }
    }

    // ─────────────────────────────────────────────────────────────────────────
    // Questions  (25 per category, 300 total)
    // ─────────────────────────────────────────────────────────────────────────

    private suspend fun insertQuestions(database: QuizDatabase) {
        val dao = database.questionDao()
        val all = mutableListOf<Question>()
        all += geoQuestions()
        all += scienceQuestions()
        all += historyQuestions()
        all += filmQuestions()
        all += musicQuestions()
        all += sportQuestions()
        all += techQuestions()
        all += foodQuestions()
        all += animalQuestions()
        all += literatureQuestions()
        all += mixedQuestions()
        all += logicQuestions()
        dao.insertAll(all)
    }

